import { useState, useEffect } from 'react';
import { Download, X, Smartphone } from 'lucide-react';
import './InstallPWA.css';

const InstallPWA = () => {
  const [supportsPWA, setSupportsPWA] = useState(false);
  const [promptInstall, setPromptInstall] = useState(null);
  const [isVisible, setIsVisible] = useState(false);
  const [isClosing, setIsClosing] = useState(false);

  useEffect(() => {
    const handler = (e) => {
      e.preventDefault();
      setSupportsPWA(true);
      setPromptInstall(e);

      // Show after a small delay to not annoy immediately
      setTimeout(() => {
        const dismissed = sessionStorage.getItem('pwa_banner_dismissed');
        if (!dismissed) {
          setIsVisible(true);
        }
      }, 3000);
    };

    window.addEventListener('beforeinstallprompt', handler);

    // Also check if already installed
    window.addEventListener('appinstalled', () => {
      handleClose();
      setSupportsPWA(false);
    });

    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleClose = () => {
    setIsClosing(true);
    // Let the slideDown animation play (0.5s)
    setTimeout(() => {
      setIsVisible(false);
      setIsClosing(false);
    }, 500);
  };

  const onClickInstall = async () => {
    if (!promptInstall) return;

    promptInstall.prompt();
    const { outcome } = await promptInstall.userChoice;

    if (outcome === 'accepted') {
      handleClose();
    }
  };

  const onDismiss = () => {
    sessionStorage.setItem('pwa_banner_dismissed', 'true');
    handleClose();
  };

  if (!isVisible) return null;

  return (
    <div className={`pwa-install-banner ${isClosing ? 'closing' : ''}`}>
      <div className="pwa-content">
        <div className="pwa-icon-box">
          <Smartphone size={24} className="pwa-icon" />
          <div className="pwa-pulse" />
        </div>
        <div className="pwa-text">
          <h3>Instalar CAMUBOX</h3>
          <p>Tenha acesso rápido e notificações instalando o app.</p>
        </div>
      </div>
      <div className="pwa-actions">
        <button className="btn-pwa-dismiss" onClick={onDismiss}>
          Agora não
        </button>
        <button className="btn-pwa-install" onClick={onClickInstall}>
          <Download size={18} />
          Instalar
        </button>
      </div>
    </div>
  );
};

export default InstallPWA;

import { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';

import Sidebar from './Sidebar';
import Topbar from './Topbar';
import './MainLayout.css';

const MainLayout = ({ children, user, onLogout }) => {
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    // Reliable Scroll Lock for Mobile (HTML + Body)
    useEffect(() => {
        const html = document.documentElement;

        if (isMobileMenuOpen) {
            html.classList.add('no-scroll');
        } else {
            html.classList.remove('no-scroll');
        }

        return () => {
            html.classList.remove('no-scroll');
        };
    }, [isMobileMenuOpen]);

    return (
        <div className="main-layout">
            <Sidebar 
                user={user}
                role={user?.isAdmin ? 'admin' : 'user'} 
                onLogout={onLogout} 
                isOpen={isMobileMenuOpen} 
                onClose={() => setIsMobileMenuOpen(false)} 
            />
            
            {isMobileMenuOpen && (
                <div className="mobile-overlay" onClick={() => setIsMobileMenuOpen(false)}></div>
            )}

            <div className={`content-area ${isMobileMenuOpen ? 'background-locked' : ''}`}>
                <Topbar user={user} onMenuToggle={() => setIsMobileMenuOpen(true)} />
                <main className="page-content">
                    {children}
                </main>
            </div>
        </div>
    );
};

export default MainLayout;

