import React, { useState, useEffect, useRef } from 'react';
import { Bell, User, Menu, X, Trash2, Check } from 'lucide-react';
import './Topbar.css';
import { dbService } from '../services/supabaseClient';

const Topbar = ({ user, onMenuToggle }) => {
    const [showNotifications, setShowNotifications] = useState(false);
    const [isClosing, setIsClosing] = useState(false);
    const [notifications, setNotifications] = useState([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const dropdownRef = useRef(null);

    const toggleNotifications = () => {
        if (showNotifications) {
            setIsClosing(true);
            setTimeout(() => {
                setShowNotifications(false);
                setIsClosing(false);
            }, 200); // Deve bater com a duração da animação no CSS
        } else {
            setShowNotifications(true);
        }
    };

    const fetchNotifications = async () => {
        if (!user?.id_usuario && !user?.uid) {
            console.log('[Topbar] No user identifier (id_usuario or uid) found in session:', user);
            return;
        }
        
        const userId = user.id_usuario;
        const userUid = user.uid;
        
        console.log(`[Topbar] Fetching notifications - id_usuario: ${userId}, uid: ${userUid}`);
        const { data, error } = await dbService.notifications.getByUser(userId, userUid);
        
        if (error) {
            console.error('[Topbar] DB ERROR during fetch:', error);
            return;
        }
        
        console.log(`[Topbar] SUCCESS: Found ${data?.length || 0} notifications`, data);
        if (data) {
            setNotifications(data);
            setUnreadCount(data.filter(n => !n.is_lida).length);
        }
    };

    useEffect(() => {
        fetchNotifications();
        // Poll for new notifications every 2 minutes
        const interval = setInterval(fetchNotifications, 120000);
        return () => clearInterval(interval);
    }, [user?.id_usuario, user?.uid]);

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
                if (showNotifications) {
                    setIsClosing(true);
                    setTimeout(() => {
                        setShowNotifications(false);
                        setIsClosing(false);
                    }, 200);
                }
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [showNotifications]);

    const handleMarkAsRead = async (id) => {
        const { error } = await dbService.notifications.markAsRead(id);
        if (!error) {
            setNotifications(notifications.map(n => n.id_notificacao === id ? { ...n, is_lida: true } : n));
            setUnreadCount(prev => Math.max(0, prev - 1));
        }
    };

    const handleDelete = async (id) => {
        const { error } = await dbService.notifications.delete(id);
        if (!error) {
            setNotifications(notifications.filter(n => n.id_notificacao !== id));
            if (!notifications.find(n => n.id_notificacao === id).is_lida) {
                setUnreadCount(prev => Math.max(0, prev - 1));
            }
        }
    };

    const formatDate = (dateStr) => {
        const date = new Date(dateStr);
        return date.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
    };

    return (
        <header className="topbar">
            <div className="topbar-left">
                <button className="mobile-menu-btn" onClick={onMenuToggle}>
                    <Menu size={24} />
                </button>
            </div>

            <div className="topbar-actions">
                <div className="notification-container" ref={dropdownRef}>
                    <button 
                        className={`icon-btn notification-btn ${unreadCount > 0 ? 'has-unread' : ''}`}
                        onClick={toggleNotifications}
                    >
                        <Bell size={20} />
                        {unreadCount > 0 && <span className="notification-badge">{unreadCount}</span>}
                    </button>

                    {showNotifications && (
                        <div className={`notification-dropdown ${isClosing ? 'closing' : ''}`}>
                            <div className="dropdown-header">
                                <h3>Notificações</h3>
                                <button className="close-btn" onClick={toggleNotifications}>
                                    <X size={18} />
                                </button>
                            </div>
                            <div className="dropdown-content">
                                {notifications.length === 0 ? (
                                    <p className="no-notifications">Nenhuma notificação por enquanto.</p>
                                ) : (
                                    notifications.map(n => (
                                        <div key={n.id_notificacao} className={`notification-item ${n.is_lida ? 'read' : 'unread'}`}>
                                            <div className="notification-info">
                                                <h4>{n.dc_titulo}</h4>
                                                <p>{n.dc_mensagem}</p>
                                                <span className="notification-date">{formatDate(n.dt_criacao)}</span>
                                            </div>
                                            <div className="notification-item-actions">
                                                {!n.is_lida && (
                                                    <button 
                                                        title="Marcar como lida" 
                                                        onClick={() => handleMarkAsRead(n.id_notificacao)}
                                                        className="action-btn read-btn"
                                                    >
                                                        <Check size={16} />
                                                    </button>
                                                )}
                                                <button 
                                                    title="Excluir" 
                                                    onClick={() => handleDelete(n.id_notificacao)}
                                                    className="action-btn delete-btn"
                                                >
                                                    <Trash2 size={16} />
                                                </button>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>

                <div className="user-profile-simple">
                    <div className="user-info">
                        <span className="user-name">{user?.name || 'Thomas Oliveira'}</span>
                        <span className="user-role">{user?.isAdmin ? 'Administrador' : 'Aluno'}</span>
                    </div>
                    <div className="avatar-circle">
                        {user?.name ? user.name.charAt(0).toUpperCase() : 'T'}
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Topbar;

import { useState, useEffect, useMemo, useCallback } from 'react';
import {
    Search,
    Filter,
    Eye,
    XCircle,
    RotateCcw,
    CreditCard,
    FileText,
    Download,
    Calendar,
    User as UserIcon,
    X,
    Loader2,
    CheckCircle2,
    Clock,
    AlertTriangle,
    MinusCircle,
    ChevronRight,
    ChevronLeft,
    MapPin,
    Tag
} from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import * as XLSX from 'xlsx';
import './AdminContracts.css';

const AdminContracts = () => {
    const [rentals, setRentals] = useState([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filters, setFilters] = useState({
        status: 'All',
        contractType: 'All',
        floor: 'All'
    });
    const [selectedRental, setSelectedRental] = useState(null);
    const [isPanelOpen, setIsPanelOpen] = useState(false);
    const [config, setConfig] = useState(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showSwapModal, setShowSwapModal] = useState(false);
    const [availableLockers, setAvailableLockers] = useState([]);
    const [isFetchingAvailable, setIsFetchingAvailable] = useState(false);
    const [modalConfig, setModalConfig] = useState({ isOpen: false, title: '', message: '', type: 'confirm', onConfirm: null });
    const [error, setError] = useState(null);
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 20;

    const mapRentalData = useCallback((data) => {
        const today = new Date();
        const mapped = [];
        
        for (const contrato of (data || [])) {
            const startDate = contrato.dt_inicio ? new Date(contrato.dt_inicio + 'T00:00:00') : null;
            const expirationDate = contrato.dt_vencimento ? new Date(contrato.dt_vencimento + 'T00:00:00') : null;

            let finalStatus = contrato.dc_status_locacao || 'ATIVA';
            if (expirationDate && expirationDate < today && finalStatus === 'ATIVA') {
                finalStatus = 'VENCIDA';
            }

            mapped.push({
                id: contrato.id_locacao,
                lockerId: contrato.id_armario,
                lockerNumber: String(contrato.nr_armario || '---'),
                student: contrato.nm_aluno || '---',
                ra: contrato.nm_ra || '---',
                floor: contrato.dc_andar || '---',
                type: contrato.dc_tipo_contrato || '---',
                contractType: contrato.dc_tipo_contrato || '---',
                startDate,
                expirationDate,
                startDateFormatted: startDate ? startDate.toLocaleDateString() : '---',
                expirationDateFormatted: expirationDate ? expirationDate.toLocaleDateString() : '---',
                status: finalStatus,
                paymentStatus: contrato.dc_status_pagamento || 'PAGO',
                sizePath: String(contrato.dc_tamanho || 'PEQUENO').toUpperCase(),
                displaySize: String(contrato.dc_tamanho || 'PEQUENO').toUpperCase() === 'GRANDE' ? 'Grande' : 'Pequeno'
            });
        }
        return mapped;
    }, []);

    const fetchRentals = useCallback(async () => {
        setIsLoading(true);
        setError(null);
        try {
            const [rentalsRes, configRes] = await Promise.all([
                dbService.rentals.getAll(),
                dbService.lockers.getConfig()
            ]);

            if (configRes.data) setConfig(configRes.data);

            const { data, error: rentalError } = rentalsRes;
            if (rentalError) throw rentalError;

            if (data) {
                const mapped = mapRentalData(data);
                setRentals(mapped);
                
                requestAnimationFrame(() => {
                    setTimeout(() => setIsLoading(false), 0);
                });
            } else {
                setRentals([]);
                setIsLoading(false);
            }
        } catch (err) {
            console.error('Runtime Error:', err);
            setError(`Erro inesperado: ${err.message}`);
            setIsLoading(false);
        }
    }, [mapRentalData]);

    useEffect(() => {
        fetchRentals();
    }, [fetchRentals]);

    const filteredRentals = useMemo(() => {
        const term = searchTerm.trim().toLowerCase();
        return rentals.filter(rental => {
            const matchesSearch = !term ||
                rental.student.toLowerCase().includes(term) ||
                rental.lockerNumber.includes(term);

            const matchesStatus = filters.status === 'All' || rental.status === filters.status;
            const matchesType = filters.contractType === 'All' || rental.contractType === filters.contractType;
            const matchesFloor = filters.floor === 'All' || rental.floor === filters.floor;

            return matchesSearch && matchesStatus && matchesType && matchesFloor;
        });
    }, [rentals, searchTerm, filters]);

    useEffect(() => {
        setCurrentPage(1);
    }, [searchTerm, filters]);

    useEffect(() => {
        const needsLock = isPanelOpen || showSwapModal;
        
        if (needsLock) {
            document.documentElement.classList.add('no-scroll');
            document.body.classList.add('no-scroll');
            
            const scrollBarWidth = window.innerWidth - document.documentElement.clientWidth;
            document.body.style.paddingRight = `${scrollBarWidth}px`;
        } else {
            document.documentElement.classList.remove('no-scroll');
            document.body.classList.remove('no-scroll');
            document.body.style.paddingRight = '';
        }
        return () => {
            document.documentElement.classList.remove('no-scroll');
            document.body.classList.remove('no-scroll');
            document.body.style.paddingRight = '';
        };
    }, [isPanelOpen, showSwapModal]);

    const handleCloseSwapModal = () => {
        setShowSwapModal(false);
    };

    const handleClosePanel = () => {
        setIsPanelOpen(false);
        setSelectedRental(null);
    };

    const openDetails = (rental) => {
        setSelectedRental(rental);
        setIsPanelOpen(true);
    };

    const totalPages = Math.ceil(filteredRentals.length / itemsPerPage);
    const paginatedRentals = useMemo(() => {
        const start = (currentPage - 1) * itemsPerPage;
        return filteredRentals.slice(start, start + itemsPerPage);
    }, [filteredRentals, currentPage]);

    const getStatusBadge = (status) => {
        switch (status) {
            case 'ATIVA':
                return <span className="status-badge active"><CheckCircle2 size={12} /> Ativo</span>;
            case 'VENCIDA':
                return <span className="status-badge expired"><AlertTriangle size={12} /> Vencido</span>;
            case 'AGUARDANDO_VISTORIA':
                return <span className="status-badge pending"><Clock size={12} /> Vistoria</span>;
            case 'CANCELADA':
            case 'ENCERRADA':
                return <span className="status-badge cancelled"><XCircle size={12} /> {status === 'ENCERRADA' ? 'Encerrado' : 'Cancelado'}</span>;
            case 'GRATUITA':
                return <span className="status-badge free"><MinusCircle size={12} /> Gratuito</span>;
            default:
                return <span className="status-badge">{status}</span>;
        }
    };

    const handleExport = () => {
        const rows = filteredRentals.map(r => ({
            'Armário': r.lockerNumber,
            'Andar': r.floor,
            'Aluno': r.student,
            'Tipo': r.contractType,
            'Início': r.startDateFormatted,
            'Vencimento': r.expirationDateFormatted,
            'Status': r.status,
            'Pagamento': r.paymentStatus
        }));

        const ws = XLSX.utils.json_to_sheet(rows);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Contratos");
        XLSX.writeFile(wb, `contratos_camubox_${new Date().toISOString().split('T')[0]}.xlsx`);
    };


    const showModal = (config) => {
        setModalConfig({
            isOpen: true,
            title: config.title || 'Confirmação',
            message: config.message || '',
            type: config.type || 'confirm',
            onConfirm: config.onConfirm || null
        });
    };

    const closeModal = () => {
        setModalConfig(prev => ({ ...prev, isOpen: false }));
    };

    const handleTerminate = async () => {
        if (!selectedRental) return;
        
        showModal({
            title: 'Encerrar Contrato',
            message: `Tem certeza que deseja encerrar o contrato de ${selectedRental.student}? Esta ação não pode ser desfeita.`,
            type: 'confirm',
            onConfirm: async () => {
                setIsSubmitting(true);
                try {
                    const { error } = await dbService.rentals.terminate(selectedRental.id, selectedRental.lockerId);
                    if (error) throw error;
                    
                    setIsPanelOpen(false);
                    await fetchRentals();
                    showModal({
                        title: 'Sucesso!',
                        message: 'Contrato encerrado com sucesso.',
                        type: 'success'
                    });
                } catch (err) {
                    showModal({
                        title: 'Erro',
                        message: 'Erro ao encerrar contrato: ' + err.message,
                        type: 'error'
                    });
                } finally {
                    setIsSubmitting(false);
                }
            }
        });
    };

    const handleSwapLockerStart = async () => {
        if (!selectedRental) return;
        setShowSwapModal(true);
        setIsFetchingAvailable(true);
        try {
            const { data } = await dbService.lockers.getAll();
            if (data) {
                const normalizeStatus = (str) => {
                    if (!str) return 'disponivel';
                    return str.normalize("NFD")
                              .replace(/[\u0300-\u036f]/g, "")
                              .toLowerCase()
                              .trim()
                              .replace(/\s+/g, '-');
                };

                // Filter only available lockers of the same size, excluding the current one
                const available = data.filter(l => {
                    const status = normalizeStatus(l.situacao || l.dc_status);
                    const lockerSize = (l.nm_tamanho || l.dc_tamanho || 'PEQUENO').toUpperCase();
                    
                    // Strict availability check
                    const isAvailable = (status === 'disponivel' || status === 'vago');
                    const isSameSize = lockerSize === selectedRental.sizePath;
                    const isDifferentLocker = l.id_armario !== selectedRental.lockerId;
                    
                    return isAvailable && isSameSize && isDifferentLocker;
                }).sort((a, b) => {
                    // Sort by floor then number
                    if (a.nm_local !== b.nm_local) return (a.nm_local || '').localeCompare(b.nm_local || '');
                    return (parseInt(a.nr_armario) || 0) - (parseInt(b.nr_armario) || 0);
                });
                setAvailableLockers(available);
            }
        } catch (err) {
            console.error('Error fetching available lockers:', err);
        } finally {
            setIsFetchingAvailable(false);
        }
    };

    const confirmSwap = async (newLocker) => {
        if (!selectedRental) return;
        
        showModal({
            title: 'Confirmar Troca',
            message: `Deseja mudar o contrato para o armário #${newLocker.nr_armario || newLocker.cd_armario}?`,
            type: 'confirm',
            onConfirm: async () => {
                setIsSubmitting(true);
                try {
                    const { error } = await dbService.rentals.updateLocker(
                        selectedRental.id,
                        selectedRental.lockerId,
                        newLocker.id_armario
                    );
                    if (error) throw error;
                    
                    setShowSwapModal(false);
                    setIsPanelOpen(false);
                    await fetchRentals();
                    showModal({
                        title: 'Sucesso!',
                        message: 'Troca de armário realizada com sucesso.',
                        type: 'success'
                    });
                } catch (err) {
                    showModal({
                        title: 'Erro',
                        message: 'Erro ao trocar armário: ' + err.message,
                        type: 'error'
                    });
                } finally {
                    setIsSubmitting(false);
                }
            }
        });
    };

    return (
        <div className="admin-contracts premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>Contratos de Armários</h1>
                    <p>Gerenciamento centralizado de todas as locações do sistema.</p>
                </div>
                <button className="secondary-btn" onClick={handleExport}>
                    <Download size={18} />
                    Exportar Excel
                </button>
            </header>

            {/* Filter Bar */}
            <div className="filter-bar-premium">
                <div className="filter-group search">
                    <span className="filter-icon"><Search size={20} /></span>
                    <input
                        type="search"
                        name="q"
                        placeholder="Buscar por aluno ou número do armário..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        autoComplete="off"
                        spellCheck="false"
                        autoCorrect="off"
                        autoCapitalize="off"
                    />
                </div>

                <div className="filter-group">
                    <span className="filter-icon"><Filter size={20} /></span>
                    <select value={filters.status} onChange={e => setFilters({ ...filters, status: e.target.value })}>
                        <option value="All">Todos os Status</option>
                        <option value="ATIVA">Ativos</option>
                        <option value="ENCERRADA">Encerrados</option>
                    </select>
                </div>

                <div className="filter-group">
                    <span className="filter-icon"><Tag size={20} /></span>
                    <select value={filters.contractType} onChange={e => setFilters({ ...filters, contractType: e.target.value })}>
                        <option value="All">Todos os Planos</option>
                        <option value="SEMESTRAL">Semestral</option>
                        <option value="ANUAL">Anual</option>
                        <option value="GRATUIDADE">Gratuidade</option>
                    </select>
                </div>
            </div>

            {/* Error State */}
            {error && (
                <div className="error-banner card">
                    <AlertTriangle size={20} />
                    <p>{error}</p>
                    <button onClick={() => window.location.reload()} className="text-btn">Recarregar</button>
                </div>
            )}

            {/* Data Area */}
            <div className="data-container">
                <div className="inspection-container card">
                    {isLoading ? (
                        <div className="loading-state-matrix" style={{ padding: '40px', textAlign: 'center' }}>
                            <Loader2 className="spinner" size={40} />
                            <p>Carregando contratos...</p>
                        </div>
                    ) : (
                        <table className="inspection-table-simple">
                            <thead>
                                <tr>
                                    <th>Armário</th>
                                    <th>Aluno</th>
                                    <th>Tipo de Contrato</th>
                                    <th>Vigência</th>
                                    <th className="col-status text-right">Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                    {paginatedRentals.map((rental, index) => (
                                        <tr 
                                            key={rental.id} 
                                            onClick={() => openDetails(rental)}
                                            className="clickable-row"
                                        >
                                        <td className="col-armario">
                                            <div className="unified-locker-badge">
                                                <span className="locker-id-part">{rental.lockerNumber}</span>
                                                <div className="floor-part">
                                                    <span>{rental.floor}</span>
                                                </div>
                                            </div>
                                        </td>
                                        
                                        <td className="col-user">
                                            <div className="info-item">
                                                <UserIcon size={14} className="icon-sub" />
                                                <div className="user-stack">
                                                    <span className="txt-main">{rental.student}</span>
                                                </div>
                                            </div>
                                        </td>

                                        <td className="col-type">
                                            <div className="info-item">
                                                <div className="type-badge-minimal">
                                                    <FileText size={14} className="icon-sub" />
                                                    <span className="txt-main">{rental.contractType}</span>
                                                </div>
                                            </div>
                                        </td>

                                        <td className="col-date">
                                            <div className="info-item">
                                                <Calendar size={14} className="icon-sub" />
                                                <span className="txt-sub">{rental.expirationDateFormatted}</span>
                                            </div>
                                        </td>

                                        <td className="col-status actions-cell">
                                            {getStatusBadge(rental.status)}
                                        </td>
                                        </tr>
                                    ))}
                                    {filteredRentals.length === 0 && (
                                        <tr>
                                            <td colSpan="5" className="empty-state">Nenhum resultado encontrado.</td>
                                        </tr>
                                    )}
                            </tbody>
                        </table>
                    )}
                </div>
                
                {!isLoading && filteredRentals.length > 0 && (
                    <div className="pagination-wrapper">
                        <div className="pagination-info">
                            Mostrando <strong>{(currentPage - 1) * itemsPerPage + 1}</strong> - <strong>{Math.min(currentPage * itemsPerPage, filteredRentals.length)}</strong> de <strong>{filteredRentals.length}</strong> contratos
                        </div>
                        <div className="pagination-controls simple">
                            <button 
                                className="pagination-btn" 
                                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} 
                                disabled={currentPage === 1}
                            >
                                <ChevronLeft size={18} />
                                <span className="btn-text">Anterior</span>
                            </button>
                            
                            <div className="pagination-status">
                                <span className="mobile-only">Pág. </span>
                                <span className="desktop-only">Página </span>
                                <strong>{currentPage}</strong> de <strong>{totalPages}</strong>
                            </div>

                            <button 
                                className="pagination-btn" 
                                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} 
                                disabled={currentPage === totalPages}
                            >
                                <span className="btn-text">Próximo</span>
                                <ChevronRight size={18} />
                            </button>
                        </div>
                    </div>
                )}
                
            </div>

            {/* Details Side Panel */}
                {isPanelOpen && (
                    <div 
                        className="details-panel-overlay" 
                        onClick={handleClosePanel}
                    >
                        <div 
                            className="details-panel" 
                            onClick={e => e.stopPropagation()}
                        >
                            <header className="panel-header">
                                <h2>Detalhes do Contrato</h2>
                                <button className="close-btn" onClick={handleClosePanel}>
                                    <X size={20} />
                                </button>
                            </header>

                            {selectedRental && (
                                <div className="panel-content">
                                    <section className="detail-section">
                                        <h3><div className="locker-icon-standard" style={{ width: '18px', height: '18px', marginRight: '8px' }} /> Dados do Armário</h3>
                                        <div className="detail-grid">
                                            <div className="detail-item full">
                                                <label>Localização / Número</label>
                                                <span>{selectedRental.floor} — #{selectedRental.lockerNumber}</span>
                                            </div>
                                            <div className="detail-item">
                                                <label>Tamanho</label>
                                                <span>{selectedRental.displaySize}</span>
                                            </div>
                                            <div className="detail-item">
                                                <label>Identificador</label>
                                                <span>ID {selectedRental.id}</span>
                                            </div>
                                        </div>
                                    </section>

                                    <section className="detail-section">
                                        <h3><UserIcon size={18} /> Aluno Responsável</h3>
                                        <div className="detail-grid">
                                            <div className="detail-item full">
                                                <label>Nome Completo</label>
                                                <strong>{selectedRental.student}</strong>
                                            </div>
                                        </div>
                                    </section>

                                    <section className="detail-section">
                                        <h3><Calendar size={18} /> Vigência do Contrato</h3>
                                        <div className="detail-grid">
                                            <div className="detail-item">
                                                <label>Tipo de Plano</label>
                                                <span>{selectedRental.contractType}</span>
                                            </div>
                                            <div className="detail-item">
                                                <label>Status Atual</label>
                                                {getStatusBadge(selectedRental.status)}
                                            </div>
                                            <div className="detail-item">
                                                <label>Início</label>
                                                <span>{selectedRental.startDateFormatted}</span>
                                            </div>
                                            <div className="detail-item">
                                                <label>Término</label>
                                                <span>{selectedRental.expirationDateFormatted}</span>
                                            </div>
                                        </div>
                                    </section>

                                    <section className="detail-section">
                                        <h3><CreditCard size={18} /> Informações Financeiras</h3>
                                        <div className="detail-grid">
                                            <div className="detail-item">
                                                <label>Status</label>
                                                <span className={`payment-status ${selectedRental.paymentStatus.toLowerCase()}`}>
                                                    {selectedRental.paymentStatus}
                                                </span>
                                            </div>
                                             <div className="detail-item">
                                                 <label>Valor da Taxa</label>
                                                 <span>
                                                     {selectedRental.contractType === 'GRATUIDADE' ? 'R$ 0,00' : (function() {
                                                         if (!config) return 'Carregando...';
                                                         const isAnual = selectedRental.contractType === 'ANUAL';
                                                         const isPequeno = selectedRental.sizePath === 'PEQUENO';
                                                         
                                                         let valor = 0;
                                                         if (isAnual) {
                                                             valor = isPequeno ? config.vl_pequeno_anual : config.vl_grande_anual;
                                                         } else {
                                                             valor = isPequeno ? config.vl_pequeno_semestral : config.vl_grande_semestral;
                                                         }
                                                         
                                                         return `R$ ${parseFloat(valor || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
                                                     })()}
                                                 </span>
                                             </div>
                                        </div>
                                    </section>

                                    {selectedRental.status === 'ATIVA' && (
                                        <div className="panel-actions">
                                            <button 
                                                className="full-width-btn btn-secondary"
                                                onClick={handleSwapLockerStart}
                                                disabled={isSubmitting}
                                            >
                                                <RotateCcw size={18} />
                                                Trocar de Armário
                                            </button>
                                            <button 
                                                className="full-width-btn btn-danger"
                                                onClick={handleTerminate}
                                                disabled={isSubmitting}
                                            >
                                                <XCircle size={18} />
                                                Encerrar Contrato
                                            </button>
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                )}
            
            {/* Swap Locker Modal */}
                {showSwapModal && (
                    <div 
                        className="details-panel-overlay swap-overlay" 
                        onClick={handleCloseSwapModal}
                    >
                        <div 
                            className="details-panel swap-modal" 
                            onClick={e => e.stopPropagation()}
                        >
                            <header className="panel-header">
                                <h2>Selecionar Novo Armário</h2>
                                <button className="close-btn" onClick={handleCloseSwapModal}>
                                    <X size={20} />
                                </button>
                            </header>
                            
                            <div className="panel-content">
                                <p className="modal-intro">
                                    Mostrando armários <strong>{selectedRental.displaySize}</strong> disponíveis.
                                </p>
                                
                                {isFetchingAvailable ? (
                                    <div className="loading-state">
                                        <Loader2 className="spinner" size={32} />
                                    </div>
                                ) : (
                                    <div className="swap-lockers-list">
                                        {availableLockers.length > 0 ? (
                                            availableLockers.map(l => (
                                                <div 
                                                    key={l.id_armario} 
                                                    className="swap-locker-card" 
                                                    onClick={() => confirmSwap(l)}
                                                >
                                                    <div className="locker-info-main">
                                                        <div className="locker-icon-box">
                                                            <div className="locker-icon-standard" style={{ width: '22px', height: '22px' }} />
                                                        </div>
                                                        <div className="locker-details-text">
                                                            <div className="locker-number-row">
                                                                <span className="locker-label">ARMÁRIO</span>
                                                                <span className="locker-number">#{String(l.nr_armario || l.cd_armario).padStart(3, '0')}</span>
                                                            </div>
                                                            <div className="floor-part-simple">
                                                                <span>{l.nm_local || l.dc_andar || 'Térreo'}</span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div className="locker-action-indicator">
                                                        <ChevronRight size={20} />
                                                    </div>
                                                    </div>
                                            ))
                                        ) : (
                                            <div className="empty-msg-container">
                                                <Search size={32} />
                                                <p>Nenhum armário disponível deste tamanho.</p>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                )}
            

            {/* Custom Action Modal */}
                {modalConfig.isOpen && (
                    <div className="action-modal-overlay">
                        <div 
                            className="action-modal-card"
                        >
                            <div className={`modal-icon-container ${modalConfig.type}`}>
                                {modalConfig.type === 'confirm' && <AlertTriangle size={32} />}
                                {modalConfig.type === 'success' && <CheckCircle2 size={32} />}
                                {modalConfig.type === 'error' && <XCircle size={32} />}
                            </div>
                            
                            <h3>{modalConfig.title}</h3>
                            <p>{modalConfig.message}</p>
                            
                            <div className="modal-footer-actions">
                                {modalConfig.type === 'confirm' ? (
                                    <>
                                        <button className="modal-btn-cancel" onClick={closeModal}>Cancelar</button>
                                        <button className="modal-btn-confirm" onClick={() => {
                                            if (modalConfig.onConfirm) modalConfig.onConfirm();
                                            closeModal();
                                        }}>Confirmar</button>
                                    </>
                                ) : (
                                    <button className="modal-btn-primary" onClick={closeModal}>Entendido</button>
                                )}
                            </div>
                        </div>
                    </div>
                )}
        </div>
    );
};

export default AdminContracts;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

import {
    CheckCircle,
    Clock,
    Wrench,
    Heart,
    LayoutGrid,
    ClipboardCheck
} from 'lucide-react';
import { dbService } from '../services/supabaseClient';
import './AdminHome.css';

const CountUp = ({ end, duration = 1500 }) => {
    const [count, setCount] = useState(0);

    useEffect(() => {
        let startTime = null;
        let animationFrameId;

        const animate = (timestamp) => {
            if (!startTime) startTime = timestamp;
            const progress = Math.min((timestamp - startTime) / duration, 1);

            // Cubic ease-out for smooth deceleration
            const easing = 1 - Math.pow(1 - progress, 3);
            const currentCount = Math.floor(easing * end);

            setCount(currentCount);

            if (progress < 1) {
                animationFrameId = requestAnimationFrame(animate);
            }
        };

        animationFrameId = requestAnimationFrame(animate);
        return () => cancelAnimationFrame(animationFrameId);
    }, [end, duration]);

    return <>{count.toLocaleString()}</>;
};

const AdminHome = () => {
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);
    const [stats, setStats] = useState([
        { label: 'Total de armários', value: 0, icon: <div className="locker-icon-standard" />, color: 'var(--primary)', key: 'total' },
        { label: 'Disponíveis', value: 0, icon: <LayoutGrid />, color: '#10b981', key: 'disponivel' },
        { label: 'Em uso', value: 0, icon: <CheckCircle />, color: '#6366f1', key: 'em-uso' },
        { label: 'Vistoria', value: 0, icon: <Clock />, color: '#f59e0b', key: 'vistoria' },
        { label: 'Manutenção', value: 0, icon: <Wrench />, color: '#94a3b8', key: 'manutencao' },
        { label: 'Gratuitos', value: 0, icon: <Heart />, color: '#8b5cf6', key: 'gratuito' },
    ]);

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);
            try {
                const { data, error } = await dbService.lockers.getAll();
                if (!error && data) {
                    const normalizeStatus = (str) => {
                        if (!str) return 'disponivel';
                        const normalized = str.normalize("NFD")
                            .replace(/[\u0300-\u036f]/g, "")
                            .toLowerCase()
                            .trim()
                            .replace(/\s+/g, '-');

                        if (normalized === 'ocupado') return 'em-uso';
                        return normalized;
                    };

                    const uniqueMap = new Map();
                    const counts = {
                        total: 0,
                        disponivel: 0,
                        'em-uso': 0,
                        'vistoria': 0,
                        manutencao: 0,
                        gratuito: 0
                    };

                    data.forEach(l => {
                        if (l.id_armario && !uniqueMap.has(l.id_armario)) {
                            const status = normalizeStatus(l.situacao || l.dc_status || 'disponivel');
                            uniqueMap.set(l.id_armario, true);

                            counts.total++;
                            if (counts.hasOwnProperty(status)) {
                                counts[status]++;
                            }
                        }
                    });

                    setStats(prev => prev.map(s => ({
                        ...s,
                        value: counts[s.key] !== undefined ? counts[s.key] : (s.key === 'total' ? counts.total : 0)
                    })));
                }
            } catch (err) {
                console.error('[FETCH ERROR]', err);
            } finally {
                setIsLoading(false);
            }
        };
        fetchData();
    }, []);

    const quickActions = [
        { label: 'Ver contratos', icon: <ClipboardCheck size={20} />, color: '#6366f1', path: '/dashboard/admin/contracts' },
        { label: 'Realizar vistoria', icon: <Clock size={20} />, color: '#f59e0b', path: '/dashboard/admin/inspections' },
        { label: 'Pendências', icon: <Wrench size={20} />, color: '#94a3b8', path: '/dashboard/admin/inspections' },
    ];

    return (
        <div className="admin-home premium-theme">
            <header className="page-header">
                <div className="header-text">
                    <h1>Visão Geral</h1>
                    <p>Status atual do sistema CAMUBOX.</p>
                </div>
            </header>

            {/* Stats Cards Row */}
            <div className="stats-grid-6">
                {stats.map((stat, i) => (
                    <div key={i} className="mini-stat-card card">
                        <div className="mini-stat-icon" style={{ backgroundColor: stat.color + '10', color: stat.color }}>
                            {stat.icon}
                        </div>
                        <div className="mini-stat-content">
                            <p className="mini-stat-label">{stat.label}</p>
                            <h3 className="mini-stat-value">
                                {isLoading ? (
                                    <span className="loading-dots">...</span>
                                ) : (
                                    <CountUp end={stat.value} />
                                )}
                            </h3>
                        </div>
                    </div>
                ))}
            </div>

            <section className="dashboard-section card">
                <h3 className="section-title">Ações Rápidas</h3>
                <div className="actions-grid-simple">
                    {quickActions.map((action, i) => (
                        <button 
                            key={i} 
                            className="action-tile-large" 
                            onClick={() => navigate(action.path)}
                        >
                            <div className="action-icon" style={{ backgroundColor: action.color + '10', color: action.color }}>
                                {action.icon}
                            </div>
                            <span>{action.label}</span>
                        </button>
                    ))}
                </div>
            </section>
        </div>
    );
};

export default AdminHome;

import { useState, useEffect } from 'react';
import { dbService } from '../services/supabaseClient';
import {
    Save,
    Shield,
    FileText,
    DollarSign,
    Settings as SettingsIcon,
    Plus,
    Trash2,
    AlertCircle,
    AlertTriangle,
    CheckCircle2,
    XCircle
} from 'lucide-react';
import { authService } from '../services/supabaseClient';
import './AdminSettings.css';

const AdminSettings = () => {
    const [config, setConfig] = useState({
        vl_pequeno_semestral: 0,
        vl_pequeno_anual: 0,
        vl_grande_semestral: 0,
        vl_grande_anual: 0,
        vl_taxa_troca: 20,
        nm_texto_contrato: ''
    });

    const [admins, setAdmins] = useState([]);
    const [newAdminEmail, setNewAdminEmail] = useState('');
    const [isLoadingAdmins, setIsLoadingAdmins] = useState(false);

    const [isLoading, setIsLoading] = useState(true);

    // Modal State
    const [modalConfig, setModalConfig] = useState({ 
        isOpen: false, 
        title: '', 
        message: '', 
        type: 'confirm', 
        onConfirm: null 
    });

    const showModal = (config) => {
        setModalConfig({
            isOpen: true,
            title: config.title || 'Confirmação',
            message: config.message || '',
            type: config.type || 'confirm',
            onConfirm: config.onConfirm || null
        });
    };

    const closeModal = () => {
        setModalConfig(prev => ({ ...prev, isOpen: false }));
    };

    const fetchAdmins = async () => {
        setIsLoadingAdmins(true);
        const { data, error } = await dbService.users.getAdmins();
        if (!error && data) {
            setAdmins(data.map(u => ({
                name: u.nm_usuario || 'Usuário',
                email: u.dc_email,
                role: 'Admin', // Default role for now
                id_usuario: u.id_usuario
            })));
        }
        setIsLoadingAdmins(false);
    };

    useEffect(() => {
        const fetchConfig = async () => {
            setIsLoading(true);
            const { data, error } = await dbService.settings.get();
            if (!error && data) {
                setConfig(prev => ({ ...prev, ...data }));
            }
            setIsLoading(false);
        };

        fetchConfig();
        fetchAdmins();
    }, []);

    const handleAddAdmin = async () => {
        const email = newAdminEmail.trim();
        if (!email) return;

        // Validar formato de e-mail
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        if (!emailRegex.test(email)) {
            showModal({
                title: 'E-mail Inválido',
                message: 'Por favor, insira um endereço de e-mail válido para continuar.',
                type: 'error'
            });
            return;
        }

        setIsLoadingAdmins(true);
        try {
            // 1. Primeiro vamos verificar se o usuário existe no sistema
            const { data: user, error: fetchError } = await dbService.users.getByEmail(email);
            
            if (fetchError || !user) {
                showModal({
                    title: 'Usuário não Encontrado',
                    message: `O e-mail ${email} ainda não está cadastrado no sistema. O usuário precisa fazer login pelo menos uma vez antes de ser promovido a admin.`,
                    type: 'error'
                });
                return;
            }

            // 2. Se existis, atualiza o status
            const { error: updateError } = await dbService.users.updateAdminStatus(email, true);
            
            if (!updateError) {
                setNewAdminEmail('');
                await fetchAdmins();
                showModal({
                    title: 'Sucesso!',
                    message: 'Novo administrador adicionado com sucesso.',
                    type: 'success'
                });
            } else {
                throw updateError;
            }
        } catch (err) {
            showModal({
                title: 'Erro',
                message: 'Não foi possível adicionar o administrador: ' + err.message,
                type: 'error'
            });
        } finally {
            setIsLoadingAdmins(false);
        }
    };

    const handleDeleteAdmin = async (email) => {
        showModal({
            title: 'Confirmar Remoção',
            message: `Tem certeza que deseja remover o acesso administrativo de ${email}?`,
            type: 'confirm',
            onConfirm: async () => {
                setIsLoadingAdmins(true);
                try {
                    const { error } = await dbService.users.updateAdminStatus(email, false);
                    if (!error) {
                        setAdmins(prev => prev.filter(a => a.email !== email));
                        showModal({
                            title: 'Sucesso!',
                            message: 'Acesso administrativo removido com sucesso.',
                            type: 'success'
                        });
                    } else {
                        throw error;
                    }
                } catch (err) {
                    showModal({
                        title: 'Erro',
                        message: 'Erro ao remover acesso: ' + err.message,
                        type: 'error'
